{
  "qa_retry_limit": 5,
  "inject_phase_reminders": true,
  "execution_mode": "strict",
  "turbo_mode": false,

  "full_auto": {
    "enabled": true,
    "max_interactions_per_phase": 50,
    "deadlock_threshold": 3,
    "escalation_mode": "pause"
  },

  "guardrails": {
    "enabled": false,
    "max_tool_calls": 400,
    "max_duration_minutes": 240,
    "max_repetitions": 10,
    "max_consecutive_errors": 5,
    "warning_threshold": 0.75,
    "idle_timeout_minutes": 60,
    "no_op_warning_threshold": 15,
    "max_coder_revisions": 5,
    "runaway_output_max_turns": 5,
    "profiles": {
      "architect": {
        "max_duration_minutes": 0,
        "max_tool_calls": 0,
        "max_consecutive_errors": 10
      }
    }
  },

  "hooks": {
    "system_enhancer": true,
    "compaction": true,
    "agent_activity": true,
    "delegation_tracker": true,
    "agent_awareness_max_chars": 300,
    "delegation_gate": true,
    "delegation_max_chars": 4000
  },

  "watchdog": {
    "scope_guard": true,
    "skip_in_turbo": false,
    "delegation_ledger": true
  },

  "self_review": {
    "enabled": true,
    "skip_in_turbo": true
  },

  "pipeline": {
    "parallel_precheck": true
  },

  "phase_complete": {
    "enabled": true,
    "required_agents": ["coder", "reviewer", "test_engineer"],
    "require_docs": true,
    "policy": "enforce",
    "regression_sweep": {
      "enforce": true
    }
  },

  "gates": {
    "syntax_check": { "enabled": true },
    "placeholder_scan": { "enabled": true },
    "sast_scan": { "enabled": true },
    "sbom_generate": { "enabled": true },
    "build_check": { "enabled": true },
    "quality_budget": {
      "enabled": true,
      "max_complexity_delta": 5,
      "max_public_api_delta": 10,
      "max_duplication_ratio": 0.05,
      "min_test_to_code_ratio": 0.3,
      "enforce_on_globs": ["src/**"],
      "exclude_globs": ["docs/**", "tests/**", "**/*.test.*"]
    }
  },

  "todo_gate": {
    "enabled": true,
    "max_high_priority": 0,
    "block_on_threshold": false
  },

  "slop_detector": {
    "enabled": true,
    "classThreshold": 3,
    "commentStripThreshold": 5,
    "diffLineThreshold": 200,
    "importHygieneThreshold": 2
  },

  "incremental_verify": {
    "enabled": true,
    "command": null,
    "timeoutMs": 30000,
    "triggerAgents": ["coder"]
  },

  "compaction_service": {
    "enabled": true,
    "observationThreshold": 40,
    "reflectionThreshold": 60,
    "emergencyThreshold": 80,
    "preserveLastNTurns": 5
  },

  "compaction_advisory": {
    "enabled": true,
    "thresholds": [50, 75, 100, 125, 150]
  },

  "context_budget": {
    "enabled": true,
    "warn_threshold": 0.7,
    "critical_threshold": 0.9,
    "model_limits": { "default": 128000 },
    "max_injection_tokens": 4000,
    "tracked_agents": ["architect"],
    "enforce": true,
    "prune_target": 0.7,
    "preserve_last_n_turns": 4,
    "recent_window": 10,
    "enforce_on_agent_switch": true,
    "tool_output_mask_threshold": 2000,
    "scoring": {
      "enabled": true,
      "max_candidates": 100
    }
  },

  "summaries": {
    "enabled": true,
    "threshold_bytes": 102400,
    "max_summary_chars": 1000,
    "max_stored_bytes": 10485760,
    "retention_days": 7,
    "exempt_tools": ["retrieve_summary", "task", "read"]
  },

  "tool_output": {
    "truncation_enabled": true,
    "max_lines": 150
  },

  "evidence": {
    "enabled": true,
    "max_age_days": 90,
    "max_bundles": 1000,
    "auto_archive": true
  },

  "checkpoint": {
    "enabled": true,
    "auto_checkpoint_threshold": 3
  },

  "review_passes": {
    "always_security_review": false,
    "security_globs": [
      "**/auth/**", "**/api/**", "**/crypto/**",
      "**/security/**", "**/middleware/**", "**/session/**", "**/token/**"
    ]
  },

  "adversarial_detection": {
    "enabled": true,
    "policy": "warn",
    "pairs": [["coder", "reviewer"]]
  },

  "adversarial_testing": {
    "enabled": true,
    "scope": "all"
  },

  "integration_analysis": {
    "enabled": true
  },

  "lint": {
    "enabled": true,
    "mode": "check",
    "linter": "auto"
  },

  "secretscan": {
    "enabled": true
  },

  "plan_cursor": {
    "enabled": true,
    "max_tokens": 1500,
    "lookahead_tasks": 2
  },

  "tool_filter": {
    "enabled": true,
    "overrides": {}
  },

  "authority": {
    "enabled": true,
    "rules": {}
  },

  "automation": {
    "mode": "hybrid",
    "capabilities": {
      "plan_sync": true,
      "evidence_auto_summaries": true,
      "decision_drift_detection": true,
      "phase_preflight": true,
      "config_doctor_on_startup": true,
      "config_doctor_autofix": true
    }
  },

  "docs": {
    "enabled": true,
    "doc_patterns": [
      "README.md", "CONTRIBUTING.md",
      "docs/**/*.md", "docs/**/*.rst", "**/CHANGELOG.md"
    ]
  },

  "ui_review": {
    "enabled": true,
    "trigger_paths": [
      "**/pages/**", "**/components/**", "**/views/**",
      "**/screens/**", "**/ui/**", "**/layouts/**"
    ],
    "trigger_keywords": [
      "new page", "new screen", "new component", "redesign",
      "layout change", "form", "modal", "dialog", "dropdown",
      "sidebar", "navbar", "dashboard", "landing page",
      "signup", "login form", "settings page", "profile page"
    ]
  },

  "knowledge": {
    "enabled": true,
    "swarm_max_entries": 100,
    "hive_max_entries": 1000,
    "auto_promote_days": 30,
    "max_inject_count": 5,
    "dedup_threshold": 0.6,
    "scope_filter": ["global"],
    "hive_enabled": true,
    "rejected_max_entries": 200,
    "validation_enabled": true,
    "evergreen_confidence": 0.9,
    "evergreen_utility": 0.8,
    "low_utility_threshold": 0.3,
    "min_retrievals_for_utility": 3,
    "schema_version": 1
  },

  "curator": {
    "enabled": true,
    "init_enabled": true,
    "phase_enabled": true,
    "max_summary_tokens": 2000,
    "min_knowledge_confidence": 0.7,
    "compliance_report": true,
    "suppress_warnings": true,
    "drift_inject_max_chars": 500
  },

  "max_iterations": 5,

  "swarms": {
    "mega": {
      "name": "Mega",
      "agents": {
        "coder": { "model": "minimax-coding-plan/MiniMax-M2.7-highspeed" },
        "explorer": { "model": "minimax-coding-plan/MiniMax-M2.7-highspeed" },
        "explore": { "model": "minimax-coding-plan/MiniMax-M2.7-highspeed" },
        "sme": { "model": "kimi-for-coding/k2p5" },
        "critic": { "model": "zai-coding-plan/glm-5.1" },
        "reviewer": { "model": "ollama-cloud/qwen3.5:397b" },
        "test_engineer": { "model": "minimax-coding-plan/MiniMax-M2.7-highspeed" },
        "docs": { "model": "minimax-coding-plan/MiniMax-M2.5-highspeed" },
        "designer": { "model": "kimi-for-coding/k2p5" }
      }
    },
    "paid": {
      "name": "Paid",
      "agents": {
        "architect": { "model": "opencode/gpt-5-nano" },
        "coder": { "model": "ollama-cloud/qwen3-coder-next" },
        "explorer": { "model": "minimax-coding-plan/MiniMax-M2.5-highspeed" },
        "explore": { "model": "minimax-coding-plan/MiniMax-M2.5-highspeed" },
        "sme": { "model": "nvidia/openai/gpt-oss-120b" },
        "critic": { "model": "zai-coding-plan/glm-5-turbo" },
        "reviewer": { "model": "minimax-coding-plan/MiniMax-M2.7-highspeed" },
        "test_engineer": { "model": "minimax-coding-plan/MiniMax-M2.5-highspeed" },
        "docs": { "model": "router/auto-fastest" },
        "designer": { "model": "kimi-for-coding/k2p5" }
      }
    },
    "lowtier": {
      "name": "lowtier",
      "agents": {
        "architect": { "model": "opencode/gpt-5-nano" },
        "coder": { "model": "ollama-cloud/qwen3-coder-next" },
        "explorer": { "model": "zai-coding-plan/glm-5-turbo" },
        "explore": { "model": "zai-coding-plan/glm-5-turbo" },
        "sme": { "model": "nvidia/openai/gpt-oss-120b" },
        "critic": { "model": "kimi-for-coding/k2p5" },
